    const generatedAnimated=this.textures.exists("generated-spritesheet"),curatedAnimated=!generatedAnimated&&this.textures.exists("curated-spritesheet"),animated=generatedAnimated||curatedAnimated,atlas=generatedAnimated?"generated-spritesheet":"curated-spritesheet",staticHero=this.textures.exists("generated-hero"),heroTexture=this.characterTexture();if(animated&&!this.anims.exists("idle")){this.anims.create({key:"idle",frames:this.anims.generateFrameNumbers(atlas,{start:0,end:3}),frameRate:5,repeat:-1});this.anims.create({key:"walk",frames:this.anims.generateFrameNumbers(atlas,{start:4,end:7}),frameRate:10,repeat:-1});this.anims.create({key:"jump",frames:this.anims.generateFrameNumbers(atlas,{start:8,end:10}),frameRate:8,repeat:0});this.anims.create({key:"dash",frames:[{key:atlas,frame:11}],frameRate:1,repeat:0});this.anims.create({key:"action",frames:this.anims.generateFrameNumbers(atlas,{start:12,end:14}),frameRate:12,repeat:0});this.anims.create({key:"plasma",frames:[{key:atlas,frame:15}],frameRate:1,repeat:0})}else if(!staticHero&&!this.anims.exists("idle")){this.anims.create({key:"idle",frames:[{key:"hero-frame-0"},{key:"hero-frame-1"}],frameRate:3,repeat:-1});this.anims.create({key:"walk",frames:[{key:"hero-frame-2"},{key:"hero-frame-3"}],frameRate:9,repeat:-1});this.anims.create({key:"action",frames:[{key:"hero-frame-4"},{key:"hero-frame-5"}],frameRate:10,repeat:0})}this.player=this.physics.add.sprite(120,platformMode?360:270,heroTexture).setDisplaySize(curatedAnimated?58:40,curatedAnimated?70:48).setCollideWorldBounds(true);if(this.anims.exists("idle"))this.player.play("idle");if(platformMode)this.physics.add.collider(this.player,this.platforms);
    this.kit.collectibleGoal=(spec.collectibles||[]).length;this.kit.enemies=this.physics.add.group();this.kit.bullets=this.physics.add.group();this.kit.lastShot=0;
