  openGate(id:string){const gate=this.kit.gates?.find((value:any)=>value.item.id===id&&!value.open);if(!gate)return;gate.open=true;gate.shape.destroy();gate.zone.destroy();gate.collider.destroy();this.record("gate:"+id)}
  damagePlayer(source:string){const now=this.time.now;if(now<this.kit.invulnerableUntil||this.kit.dashUntil>now)return;this.kit.invulnerableUntil=now+(spec.movement?.invulnerabilityMs||220);this.kit.hp--;this.player.setTintFill(0xffffff);this.time.delayedCall(100,()=>this.player?.active&&this.player.clearTint());this.record("damage:"+source);if(this.kit.hp<=0)return this.finish("failure");this.player.setPosition(this.kit.respawn.x,this.kit.respawn.y);(this.player.body as Phaser.Physics.Arcade.Body).setVelocity(0,0);this.updateMetroidvaniaStatus()}
