  melee(time:number){if(time<(this.kit.nextMelee||0))return;this.kit.combo=time<this.kit.comboUntil?(this.kit.combo+1)%3:0;this.kit.comboUntil=time+spec.combat.comboWindowMs;this.kit.nextMelee=time+170;const damage=spec.combat.meleeCombo[this.kit.combo],facing=this.player.flipX?-1:1;for(const group of[this.kit.enemies,this.kit.crates])for(const target of group?.getChildren?.()||[])if(target.active&&Math.abs(target.x-(this.player.x+facing*34))<spec.combat.meleeRange&&Math.abs(target.y-this.player.y)<70)this.hitTarget(null,target,damage);if(this.anims.exists("action"))this.player.play("action",true);this.record("action:melee:"+(this.kit.combo+1));this.tone(180+this.kit.combo*70,.06)}
  updateMetroidvania(time:number,body:Phaser.Physics.Arcade.Body){this.kit.energy=Math.min(spec.combat.maxEnergy,this.kit.energy+spec.combat.energyRechargePerSecond/60);for(const gate of this.kit.gates||[])if(!gate.open&&this.kit.abilities.has(gate.item.requires))this.openGate(gate.item.id);for(const enemy of this.kit.enemies?.getChildren?.()||[]){if(!enemy.active)continue;const kind=enemy.getData("kind"),distance=this.player.x-enemy.x;if(kind==="patrol_drone"){enemy.x=enemy.getData("originX")+Math.sin(time/700)*55;if(Math.abs(distance)<enemy.getData("range")&&time>enemy.getData("nextAttack")){enemy.setData("nextAttack",time+1700);const shot=this.physics.add.sprite(enemy.x,enemy.y,"ball").setTint(0xff315c).setVelocityX(Math.sign(distance)*230);this.physics.add.overlap(this.player,shot,()=>{shot.destroy();this.damagePlayer("drone")})}}else if(kind==="scrapper_bot"&&Math.abs(distance)<enemy.getData("range")){enemy.setVelocityX(Math.sign(distance)*105);if(time>enemy.getData("nextAttack")){enemy.setData("nextAttack",time+1300);enemy.setTint(0xff315c);this.time.delayedCall(240,()=>enemy.active&&enemy.clearTint())}}else if((kind==="turret"||kind==="boss")&&time>enemy.getData("nextAttack")){enemy.setData("nextAttack",time+(kind==="boss"?1100:3000));const shot=this.physics.add.sprite(enemy.x,enemy.y,"ball").setTint(0xff315c).setVelocityX(Math.sign(distance)*260);this.physics.add.overlap(this.player,shot,()=>{shot.destroy();this.damagePlayer(kind)})}}this.updateMetroidvaniaStatus()}
  updateMetroidvaniaStatus(){if(this.kit.status)this.kit.status.setText("HP "+this.kit.hp+"   ENERGY "+Math.floor(this.kit.energy)+"   ABILITIES "+this.kit.abilities.size+"/"+spec.abilities.length+"   SCORE "+this.score)}
  fire(time:number){if(time<this.kit.lastShot||!this.player)return;if(spec.template==="metroidvania"){if(this.kit.energy<spec.combat.plasmaEnergyCost)return;this.kit.energy-=spec.combat.plasmaEnergyCost}this.kit.lastShot=time+(spec.fireRate||spec.shells?.cooldownMs||300);const direction=this.player.flipX?-1:1,bullet=this.physics.add.sprite(this.player.x+direction*28,this.player.y,"ball").setVelocityX(direction*(spec.shells?.speed?spec.shells.speed*45:520));this.kit.bullets.add(bullet);if(this.anims.exists(spec.template==="metroidvania"?"plasma":"action"))this.player.play(spec.template==="metroidvania"?"plasma":"action",true);this.record("action:fire");this.tone(320,.05);this.updateMetroidvaniaStatus()}
  createSnake(){this.physics.world.gravity.y=0;this.snake=(spec.snake.start as any[]).map(v=>({...v}));this.food={...spec.food};}
  createBlocks(){this.physics.world.gravity.y=0;this.kit.board=Array.from({length:spec.board.rows},()=>Array(spec.board.cols).fill(0));this.kit.active={x:4,y:0,shape:[[0,0],[1,0],[0,1],[1,1]]};this.kit.dropAt=0;this.kit.cells=[];this.renderBlocks()}
  renderBlocks(){for(const cell of this.kit.cells||[])cell.destroy();this.kit.cells=[];const size=24,ox=(W-spec.board.cols*size)/2,oy=82,active=this.kit.active;for(let y=0;y<spec.board.rows;y++)for(let x=0;x<spec.board.cols;x++)if(this.kit.board[y][x])this.kit.cells.push(this.add.rectangle(ox+x*size,oy+y*size,size-2,size-2,color(spec.art.palette[1])).setOrigin(0));for(const[pX,pY]of active.shape)this.kit.cells.push(this.add.rectangle(ox+(active.x+pX)*size,oy+(active.y+pY)*size,size-2,size-2,color(spec.art.palette[2])).setOrigin(0))}
