export function projectFingerprint(project) {
  let h = 2166136261;
  const text = JSON.stringify(project);
  for (const c of text) h = Math.imul(h ^ c.charCodeAt(0), 16777619);
  return (h >>> 0).toString(16).padStart(8, "0");
}

